use std::collections::BTreeMap;

use crate::Certificate;
use crate::Identifier;
use crate::URI;
use crate::cbor_string_map_struct::cbor_string_map_struct;

cbor_string_map_struct! {
    #[derive(Debug, Clone, PartialEq, Eq)]
    pub struct IdentifierList {
        required {
            pub identifiers: BTreeMap<Identifier, IdentifierInfo> => "identifiers",
        }
        optional {
            pub aggregation_uri: String => "aggregation_uri",
        }
    }
}

cbor_string_map_struct! {
    #[derive(Debug, Clone, PartialEq, Eq)]
    pub struct IdentifierInfo {
        required {
        }
        optional {
        }
    }
}

cbor_string_map_struct! {
    #[derive(Debug, Clone, PartialEq, Eq)]
    pub struct IdentifierListInfo {
        required {
            pub id: Identifier => "id",
            pub uri: URI => "uri",
        }
        optional {
            pub certificate: Certificate => "certificate",
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::{CborAny, CborWebToken, CoseSign1, GetCosePayload, HeaderMap};
    use minicbor::bytes::ByteVec;
    use minicbor::data::Tagged;
    const FIXTURE: &str = "";

    #[test]
    fn identifier_list_roundtrip() {
        let list = IdentifierList {
            identifiers: BTreeMap::from([(ByteVec::from(vec![0xAA; 4]), IdentifierInfo {})]),
            aggregation_uri: Some("https://example.com/aggregate".to_string()),
        };

        let encoded = minicbor::to_vec(&list).unwrap();
        let decoded: IdentifierList = minicbor::decode(&encoded).unwrap();
        assert_eq!(decoded, list);
    }

    #[test]
    fn cbor_web_token_decodes_captured_identifier_list() {
        let fixture = hex::decode(FIXTURE).unwrap();
        let sign1: CoseSign1<CborAny> =
            minicbor::decode::<Tagged<18, CoseSign1<CborAny>>>(&fixture)
                .unwrap()
                .into_value();
        let protected: HeaderMap = sign1.protected.decode().unwrap();

        assert_eq!(protected.typ, Some("identifierlist+cwt".to_string()));
        assert!(protected.x5chain.is_some());

        let token: CborWebToken =
            minicbor::decode(sign1.payload().unwrap().raw_cbor_bytes()).unwrap();
        assert!(token.exp > 0);
        assert!(!token.identifier_list.identifiers.is_empty());
    }

    #[test]
    fn header_map_roundtrips_typ_string() {
        let header = HeaderMap {
            alg: None,
            typ: Some("application/identifierlist+cwt".to_string()),
            x5chain: None,
        };

        let encoded = minicbor::to_vec(&header).unwrap();
        let decoded: HeaderMap = minicbor::decode(&encoded).unwrap();
        assert_eq!(decoded, header);
    }
}
